   193→static int
   194→set_firewall_rule(char *addr, int add)
   195→{
   196→    char cli[256];
   197→    struct cork_ip ip;
   198→
   199→    if (getuid() != 0)
   200→        return -1;
   201→
   202→    if (cork_ip_init(&ip, addr))
   203→        return -1;
   204→
   205→    if (add) {
   206→        if (mode == IPTABLES_MODE)
   207→            sprintf(cli, ip.version == 4 ? iptables_add_rule : ip6tables_add_rule,
   208→                    chain_name, addr);
   209→        else if (mode == FIREWALLD_MODE)
   210→            sprintf(cli, ip.version == 4 ? firewalld_add_rule : firewalld6_add_rule,
   211→                    chain_name, addr);
   212→        return run_cmd(cli);
   213→    } else {
   214→        if (mode == IPTABLES_MODE)
   215→            sprintf(cli, ip.version == 4 ? iptables_remove_rule : ip6tables_remove_rule,
   216→                    chain_name, addr);
   217→        else if (mode == FIREWALLD_MODE)
   218→            sprintf(cli, ip.version == 4 ? firewalld_remove_rule : firewalld6_remove_rule,
   219→                    chain_name, addr);
   220→        return run_cmd(cli);
   221→    }
   222→
   223→    return 0;
   224→}
