   363→int
   364→init_acl(const char *path)
   365→{
   366→    // initialize ipset
   367→    ipset_init_library();
   368→
   369→    ipset_init(&white_list_ipv4);
   370→    ipset_init(&white_list_ipv6);
   371→    ipset_init(&black_list_ipv4);
   372→    ipset_init(&black_list_ipv6);
   373→    ipset_init(&outbound_block_list_ipv4);
   374→    ipset_init(&outbound_block_list_ipv6);
   375→
   376→    cork_dllist_init(&black_list_rules);
   377→    cork_dllist_init(&white_list_rules);
   378→    cork_dllist_init(&outbound_block_list_rules);
   379→
   380→    struct ip_set *list_ipv4  = &black_list_ipv4;
   381→    struct ip_set *list_ipv6  = &black_list_ipv6;
   382→    struct cork_dllist *rules = &black_list_rules;
   383→
   384→    FILE *f = fopen(path, "r");
   385→    if (f == NULL) {
   386→        LOGE("Invalid acl path.");
   387→        return -1;
   388→    }
   389→
   390→    char buf[257];
   391→    while (!feof(f))
   392→        if (fgets(buf, 256, f)) {
   393→            // Trim the newline
   394→            int len = strlen(buf);
   395→            if (len > 0 && buf[len - 1] == '\n') {
   396→                buf[len - 1] = '\0';
   397→            }
   398→
   399→            char *line = trimwhitespace(buf);
   400→
   401→            // Skip comments
   402→            if (line[0] == '#') {
   403→                continue;
   404→            }
   405→
   406→            if (strlen(line) == 0) {
   407→                continue;
   408→            }
   409→
   410→            if (strcmp(line, "[outbound_block_list]") == 0) {
   411→                list_ipv4 = &outbound_block_list_ipv4;
   412→                list_ipv6 = &outbound_block_list_ipv6;
   413→                rules     = &outbound_block_list_rules;
   414→                continue;
   415→            } else if (strcmp(line, "[black_list]") == 0
   416→                       || strcmp(line, "[bypass_list]") == 0) {
   417→                list_ipv4 = &black_list_ipv4;
   418→                list_ipv6 = &black_list_ipv6;
   419→                rules     = &black_list_rules;
   420→                continue;
   421→            } else if (strcmp(line, "[white_list]") == 0
   422→                       || strcmp(line, "[proxy_list]") == 0) {
   423→                list_ipv4 = &white_list_ipv4;
   424→                list_ipv6 = &white_list_ipv6;
   425→                rules     = &white_list_rules;
   426→                continue;
   427→            } else if (strcmp(line, "[reject_all]") == 0
   428→                       || strcmp(line, "[bypass_all]") == 0) {
   429→                acl_mode = WHITE_LIST;
   430→                continue;
   431→            } else if (strcmp(line, "[accept_all]") == 0
   432→                       || strcmp(line, "[proxy_all]") == 0) {
   433→                acl_mode = BLACK_LIST;
   434→                continue;
   435→            }
   436→
   437→            char host[257];
   438→            int cidr;
   439→            parse_addr_cidr(line, host, &cidr);
   440→
   441→            struct cork_ip addr;
   442→            int err = cork_ip_init(&addr, host);
   443→            if (!err) {
   444→                if (addr.version == 4) {
   445→                    if (cidr >= 0) {
   446→                        ipset_ipv4_add_network(list_ipv4, &(addr.ip.v4), cidr);
   447→                    } else {
   448→                        ipset_ipv4_add(list_ipv4, &(addr.ip.v4));
   449→                    }
   450→                } else if (addr.version == 6) {
   451→                    if (cidr >= 0) {
   452→                        ipset_ipv6_add_network(list_ipv6, &(addr.ip.v6), cidr);
   453→                    } else {
   454→                        ipset_ipv6_add(list_ipv6, &(addr.ip.v6));
   455→                    }
   456→                }
   457→            } else {
   458→                rule_t *rule = new_rule();
   459→                accept_rule_arg(rule, line);
   460→                init_rule(rule);
   461→                add_rule(rules, rule);
   462→            }
   463→        }
   464→
   465→    fclose(f);
   466→
   467→    return 0;
   468→}
   469→
   470→void
   471→free_rules(struct cork_dllist *rules)
   472→{
   473→    struct cork_dllist_item *iter;
   474→    while ((iter = cork_dllist_head(rules)) != NULL) {
   475→        rule_t *rule = cork_container_of(iter, rule_t, entries);
   476→        remove_rule(rule);
   477→    }
   478→}
   479→
   480→void
   481→free_acl(void)
   482→{
   483→    ipset_done(&black_list_ipv4);
   484→    ipset_done(&black_list_ipv6);
   485→    ipset_done(&white_list_ipv4);
   486→    ipset_done(&white_list_ipv6);
   487→
   488→    free_rules(&black_list_rules);
   489→    free_rules(&white_list_rules);
   490→}
