static int
run_cmd(const char *cmd)
{
    int ret = 0;
    char cmdstring[256];

    sprintf(cmdstring, "%s\n", cmd);
    size_t len = strlen(cmdstring);

    if (shell_stdin != NULL) {
        ret = fwrite(cmdstring, 1, len, shell_stdin);
        fflush(shell_stdin);
    }

    return ret == len;
}

static int
init_firewall()

